UPDATE challenges
SET
  starter_files = '[{"path": "auth.js", "content": "// auth.js - JWT-based authentication (contains 5 bugs - find and fix them all)\nconst crypto = require(''node:crypto'');\n\nconst SECRET = ''supersecret'';\nconst tokenStore = new Set(); // active tokens\n\n/**\n * Hash a password using SHA-256 (should use bcrypt in production).\n * BUG 1: passwords are NOT hashed before storing \u2014 plaintext stored instead.\n */\nfunction hashPassword(password) {\n  // BUG 1: missing hash \u2014 returning plaintext\n  return password;\n}\n\nfunction verifyPassword(password, hash) {\n  return hashPassword(password) === hash;\n}\n\n/**\n * Simple base64url helper (no external deps).\n */\nfunction b64url(str) {\n  return Buffer.from(str).toString(''base64url'');\n}\nfunction b64urlDecode(str) {\n  return Buffer.from(str, ''base64url'').toString(''utf8'');\n}\n\n/**\n * Create a signed JWT (HS256-like, using HMAC-SHA256).\n */\nfunction createToken(payload) {\n  const header = b64url(JSON.stringify({ alg: ''HS256'', typ: ''JWT'' }));\n  const body   = b64url(JSON.stringify(payload));\n  const sig    = crypto.createHmac(''sha256'', SECRET).update(`${header}.${body}`).digest(''base64url'');\n  const token  = `${header}.${body}.${sig}`;\n  tokenStore.add(token);\n  return token;\n}\n\n/**\n * Verify and decode a JWT.\n * BUG 3: does NOT check token expiration.\n */\nfunction verifyToken(token) {\n  if (!token) throw new Error(''No token provided'');\n  if (!tokenStore.has(token)) throw new Error(''Token invalidated'');\n\n  const parts = token.split(''.'');\n  if (parts.length !== 3) throw new Error(''Malformed token'');\n\n  const [header, body, sig] = parts;\n  const expectedSig = crypto.createHmac(''sha256'', SECRET).update(`${header}.${body}`).digest(''base64url'');\n  if (sig !== expectedSig) throw new Error(''Invalid signature'');\n\n  const payload = JSON.parse(b64urlDecode(body));\n\n  // BUG 3: expiry is never checked \u2014 expired tokens are accepted\n  // if (payload.exp && Date.now() / 1000 > payload.exp) throw new Error(''Token expired'');\n\n  return payload;\n}\n\n// In-memory user store\nconst users = {};\n\n/**\n * Register a new user.\n */\nfunction register(email, password) {\n  if (users[email]) throw new Error(''User already exists'');\n  users[email] = { email, password: hashPassword(password) };\n  return { success: true };\n}\n\n/**\n * Login: returns a JWT on success.\n * BUG 2: returns status 403 on invalid credentials instead of 401.\n */\nfunction login(email, password) {\n  const user = users[email];\n  if (!user || !verifyPassword(password, user.password)) {\n    // BUG 2: wrong status code \u2014 should be 401\n    return { status: 403, error: ''Invalid credentials'' };\n  }\n  const token = createToken({\n    sub: email,\n    iat: Math.floor(Date.now() / 1000),\n    exp: Math.floor(Date.now() / 1000) + 3600,\n  });\n  return { status: 200, token };\n}\n\n/**\n * Logout: should invalidate the token.\n * BUG 5: does NOT remove token from tokenStore.\n */\nfunction logout(token) {\n  // BUG 5: token is NOT invalidated \u2014 it stays in tokenStore\n  // tokenStore.delete(token);\n  return { success: true };\n}\n\nmodule.exports = { register, login, logout, verifyToken, hashPassword };\n"}, {"path": "middleware.js", "content": "// middleware.js - Express-style middleware for protected routes (contains 1 bug)\nconst { verifyToken } = require(''./auth'');\n\n/**\n * Middleware that checks for a valid JWT in the Authorization header.\n * BUG 4: does NOT correctly extract the Bearer token.\n * It passes the full header value (e.g. \"Bearer eyJ...\") to verifyToken\n * instead of stripping the \"Bearer \" prefix.\n */\nfunction requireAuth(req, res, next) {\n  const authHeader = req.headers && req.headers[''authorization''];\n  if (!authHeader) {\n    res.status = 401;\n    res.body = { error: ''No authorization header'' };\n    return;\n  }\n\n  // BUG 4: passing the full header instead of just the token\n  const token = authHeader; // should be: authHeader.replace(/^Bearer\\s+/i, '''')\n\n  try {\n    const payload = verifyToken(token);\n    req.user = payload;\n    next();\n  } catch (err) {\n    res.status = 401;\n    res.body = { error: err.message };\n  }\n}\n\nmodule.exports = { requireAuth };\n"}]',
  test_suite    = '[{"file_path": "test.js", "content": "// test.js - Test suite for debug-auth-flow challenge\n// Uses only node:assert and node:crypto \u2014 no npm install required\n// DO NOT MODIFY THIS FILE\n''use strict'';\n\nconst assert = require(''node:assert'');\nconst { register, login, logout, verifyToken, hashPassword } = require(''./auth'');\nconst { requireAuth } = require(''./middleware'');\n\nlet passed = 0;\nlet failed = 0;\nconst total = 5;\n\nfunction test(name, fn) {\n  try {\n    fn();\n    console.log(`  PASS: ${name}`);\n    passed++;\n  } catch (err) {\n    console.log(`  FAIL: ${name}`);\n    console.log(`        ${err.message}`);\n    failed++;\n  }\n}\n\n// \u2500\u2500 Test 1: passwords must be hashed (not stored as plaintext) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntest(''Bug 1: registration hashes the password'', () => {\n  const hash = hashPassword(''mysecret'');\n  assert.notStrictEqual(hash, ''mysecret'',\n    ''hashPassword should NOT return the plaintext password'');\n  assert.ok(hash.length >= 32,\n    ''hash should be at least 32 chars (hex/base64 of SHA-256)'');\n});\n\n// \u2500\u2500 Test 2: login returns 401 on bad credentials, not 403 \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntest(''Bug 2: login returns 401 for invalid credentials'', () => {\n  register(''user2@test.com'', ''correctpass'');\n  const result = login(''user2@test.com'', ''wrongpass'');\n  assert.strictEqual(result.status, 401,\n    `Expected status 401 but got ${result.status}`);\n});\n\n// \u2500\u2500 Test 3: verifyToken rejects expired tokens \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntest(''Bug 3: verifyToken throws on expired token'', () => {\n  // Monkey-patch Date.now to create a token whose exp is far in the past,\n  // then restore the clock before calling verifyToken.\n  const realDateNow = Date.now;\n  Date.now = () => 0; // epoch \u2014 token exp = 0 + 3600 = 3600 (seconds since epoch)\n  register(''exptest@test.com'', ''pass'');\n  const loginRes = login(''exptest@test.com'', ''pass'');\n  Date.now = realDateNow; // restore real clock (now >> 3600s since epoch)\n\n  assert.strictEqual(loginRes.status, 200, ''Setup: login should succeed with past clock'');\n  assert.throws(\n    () => verifyToken(loginRes.token),\n    /expired/i,\n    ''verifyToken should throw \"Token expired\" for a token whose exp is in the past''\n  );\n});\n\n// \u2500\u2500 Test 4: middleware extracts Bearer token correctly \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntest(''Bug 4: middleware extracts Bearer token from Authorization header'', () => {\n  register(''mw@test.com'', ''pass'');\n  const loginRes = login(''mw@test.com'', ''pass'');\n  assert.strictEqual(loginRes.status, 200, ''Setup: login should succeed'');\n\n  const req = { headers: { authorization: `Bearer ${loginRes.token}` } };\n  const res = {};\n  let nextCalled = false;\n  requireAuth(req, res, () => { nextCalled = true; });\n\n  assert.ok(nextCalled,\n    ''next() should be called when a valid Bearer token is provided'');\n  assert.ok(req.user && req.user.sub === ''mw@test.com'',\n    ''req.user should be set with the decoded payload'');\n});\n\n// \u2500\u2500 Test 5: logout invalidates the token \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntest(''Bug 5: logout invalidates the token'', () => {\n  register(''logout@test.com'', ''pass'');\n  const loginRes = login(''logout@test.com'', ''pass'');\n  assert.strictEqual(loginRes.status, 200, ''Setup: login should succeed'');\n\n  const token = loginRes.token;\n  assert.ok(verifyToken(token), ''Token should be valid before logout'');\n\n  logout(token);\n\n  assert.throws(\n    () => verifyToken(token),\n    /invalidated|invalid/i,\n    ''verifyToken should throw after logout''\n  );\n});\n\n// \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconsole.log('''');\nconsole.log(`${passed} passed, ${failed} failed out of ${total}`);\nprocess.exit(failed > 0 ? 1 : 0);\n", "command": "node test.js"}]'
WHERE slug = 'debug-auth-flow';

UPDATE challenges
SET
  starter_files = '[{"path": "dashboard.js", "content": "// dashboard.js - Simulated dashboard API (contains 3 testable performance bugs)\n// BUG 1 (n-plus-one-items): fetches order items one-by-one in a loop\n// BUG 2 (parallel-async): profile + orders fetched sequentially instead of in parallel\n// BUG 3 (select-star): returns all fields on orders instead of only 3 needed fields\n''use strict'';\n\n// \u2500\u2500\u2500 Simulated async DB / service calls \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nfunction delay(ms) {\n  return new Promise(resolve => setTimeout(resolve, ms));\n}\n\n/** Simulate a DB call that takes ~20ms each. */\nasync function dbGetUser(userId) {\n  await delay(20);\n  return { id: userId, name: ''Alice'', email: ''alice@example.com'', role: ''admin'',\n           createdAt: ''2022-01-01'', updatedAt: ''2024-01-01'', passwordHash: ''x'',\n           sessionToken: ''abc123'', preferences: ''{}'' };\n}\n\n/** Simulate fetching orders \u2014 returns ALL columns (select-star bug). */\nasync function dbGetOrders(userId) {\n  await delay(20);\n  return Array.from({ length: 5 }, (_, i) => ({\n    id: i + 1,\n    userId,\n    status: ''shipped'',\n    createdAt: ''2024-01-01'',\n    total: (i + 1) * 10,\n    shippingAddress: ''123 Main St'',\n    billingAddress: ''123 Main St'',\n    paymentMethod: ''card'',\n    discountCode: null,\n    notes: '''',\n    trackingNumber: ''TRK'' + i,\n    carrier: ''UPS'',\n    estimatedDelivery: ''2024-01-10'',\n    actualDelivery: null,\n    returnReason: null,\n    refundAmount: 0,\n  }));\n}\n\n/** Fetch items for a SINGLE order (used in N+1 pattern). */\nasync function dbGetOrderItems(orderId) {\n  await delay(10);\n  return [{ orderId, productId: 1, qty: 2, price: 5 }];\n}\n\n/** Fetch items for ALL orders in one batch query (correct approach). */\nasync function dbGetAllOrderItems(orderIds) {\n  await delay(10);\n  return orderIds.flatMap(orderId => [{ orderId, productId: 1, qty: 2, price: 5 }]);\n}\n\n// \u2500\u2500\u2500 Dashboard implementations \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n/**\n * BUGGY: contains all 3 bugs.\n */\nasync function getDashboard(userId) {\n  const calls = [];\n  const timings = {};\n\n  // BUG 2: sequential \u2014 profile fetched first, then orders\n  timings.getUserStart = Date.now();\n  const profile = await dbGetUser(userId);\n  timings.getUserEnd = Date.now();\n  calls.push(''getUser'');\n\n  timings.getOrdersStart = Date.now();\n  const orders = await dbGetOrders(userId);\n  timings.getOrdersEnd = Date.now();\n  calls.push(''getOrders'');\n\n  // BUG 1: N+1 \u2014 items fetched one order at a time\n  const itemsMap = {};\n  for (const order of orders) {\n    itemsMap[order.id] = await dbGetOrderItems(order.id);\n    calls.push(''getOrderItems:'' + order.id);\n  }\n\n  // BUG 3: returning all order fields instead of just id/createdAt/total\n  const orderSummaries = orders.map(o => ({ ...o, items: itemsMap[o.id] }));\n\n  const grandTotal = orderSummaries.reduce((sum, o) => sum + o.total, 0);\n\n  return { profile, orders: orderSummaries, grandTotal, _calls: calls, _timings: timings };\n}\n\nmodule.exports = { getDashboard, dbGetUser, dbGetOrders, dbGetOrderItems, dbGetAllOrderItems };\n"}]',
  test_suite    = '[{"file_path": "test.js", "content": "// test.js - Test suite for performance-bottleneck challenge\n// Uses only node:assert \u2014 no npm install required\n// DO NOT MODIFY THIS FILE\n''use strict'';\n\nconst assert = require(''node:assert'');\nconst { getDashboard } = require(''./dashboard'');\n\nlet passed = 0;\nlet failed = 0;\nconst total = 3;\n\nfunction test(name, fn) {\n  return Promise.resolve()\n    .then(() => fn())\n    .then(() => { console.log(`  PASS: ${name}`); passed++; })\n    .catch(err => { console.log(`  FAIL: ${name}`); console.log(`        ${err.message}`); failed++; });\n}\n\nasync function run() {\n\n  // \u2500\u2500 Test 1: N+1 query \u2014 items must be batch-fetched \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  await test(''Trap 1 (n-plus-one-items): order items fetched in a single batch call'', async () => {\n    const result = await getDashboard(''user-1'');\n    const perOrderCalls = result._calls.filter(c => c.startsWith(''getOrderItems:''));\n    assert.strictEqual(perOrderCalls.length, 0,\n      `Expected 0 per-order item calls (batch instead), but got ${perOrderCalls.length} \u2014 N+1 bug present`);\n    const batchCalls = result._calls.filter(c => c === ''getAllOrderItems'');\n    assert.ok(batchCalls.length >= 1, ''Expected at least one getAllOrderItems batch call'');\n  });\n\n  // \u2500\u2500 Test 2: parallel async \u2014 profile + orders must be parallel \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  await test(''Trap 2 (parallel-async): user profile and orders fetched in parallel'', async () => {\n    const result = await getDashboard(''user-2'');\n    const t = result._timings;\n    // In sequential mode the getOrders fetch starts AFTER getUser completes.\n    // In parallel mode getOrders starts before (or at the same time as) getUser ends.\n    // Sequential condition: getOrdersStart >= getUserEnd\n    const isSequential = t.getOrdersStart >= t.getUserEnd;\n    assert.ok(!isSequential,\n      `getOrders fetch starts at ${t.getOrdersStart}, but getUser ends at ${t.getUserEnd} \u2014 ` +\n      `fetches are sequential (parallel-async bug present)`);\n  });\n\n  // \u2500\u2500 Test 3: select-star \u2014 order objects must contain only id/createdAt/total\n  await test(''Trap 3 (select-star): order summaries contain only id, createdAt, total fields'', async () => {\n    const result = await getDashboard(''user-3'');\n    assert.ok(result.orders.length > 0, ''Should return at least one order'');\n    const order = result.orders[0];\n    const keys = Object.keys(order).filter(k => k !== ''items'');\n    const extraKeys = keys.filter(k => ![''id'', ''createdAt'', ''total''].includes(k));\n    assert.strictEqual(extraKeys.length, 0,\n      `Order has extra fields beyond id/createdAt/total: ${extraKeys.join('', '')} \u2014 select-star bug present`);\n  });\n\n  // \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  console.log('''');\n  console.log(`${passed} passed, ${failed} failed out of ${total}`);\n  process.exit(failed > 0 ? 1 : 0);\n}\n\nrun().catch(err => {\n  console.error(''Unexpected error:'', err);\n  process.exit(1);\n});\n", "command": "node test.js"}]'
WHERE slug = 'performance-bottleneck';

UPDATE challenges
SET
  starter_files = '[{"path": "ProfilePage.js", "content": "// ProfilePage.js\n// A monolithic module that handles user profiles.\n// Refactor this into clean, well-structured code:\n//   - Break into smaller, focused modules/components\n//   - Extract hooks/helpers for data fetching and form state\n//   - Add proper TypeScript-style JSDoc types\n//   - Maintain all existing functionality\n//   - Improve error handling\n''use strict'';\n\n// \u2500\u2500 Fake fetch helper \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function apiFetch(url, options) {\n  // Simulate network call\n  return { ok: true, json: async () => ({ success: true }) };\n}\n\n// \u2500\u2500 Everything in one giant function \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n/**\n * @param {{ userId: string }} props\n */\nasync function ProfilePage(props) {\n  // State (would be useState in React)\n  let user = null;\n  let isLoading = true;\n  let isEditing = false;\n  let error = null;\n  let formName = '''';\n  let formEmail = '''';\n  let formBio = '''';\n  let avatar = null;\n  let avatarPreview = null;\n  let isUploadingAvatar = false;\n  let avatarError = null;\n  let activity = [];\n  let activityLoading = true;\n  let activityError = null;\n  let saveError = null;\n  let isSaving = false;\n\n  // Fetch user data\n  try {\n    const res = await apiFetch(`/api/users/${props.userId}`);\n    if (!res.ok) throw new Error(''Failed to fetch user'');\n    const data = await res.json();\n    user = data;\n    formName = data.name || '''';\n    formEmail = data.email || '''';\n    formBio = data.bio || '''';\n    isLoading = false;\n  } catch (e) {\n    error = e.message;\n    isLoading = false;\n  }\n\n  // Fetch activity\n  try {\n    const res = await apiFetch(`/api/users/${props.userId}/activity`);\n    if (!res.ok) throw new Error(''Failed to fetch activity'');\n    const data = await res.json();\n    activity = data.items || [];\n    activityLoading = false;\n  } catch (e) {\n    activityError = e.message;\n    activityLoading = false;\n  }\n\n  // Handle avatar upload\n  async function handleAvatarChange(file) {\n    if (!file) return;\n    if (![''image/jpeg'', ''image/png'', ''image/webp''].includes(file.type)) {\n      avatarError = ''Invalid file type. Use JPEG, PNG or WebP.'';\n      return;\n    }\n    if (file.size > 5 * 1024 * 1024) {\n      avatarError = ''File too large. Max 5MB.'';\n      return;\n    }\n    avatarError = null;\n    avatarPreview = URL.createObjectURL ? URL.createObjectURL(file) : null;\n    avatar = file;\n    isUploadingAvatar = true;\n    try {\n      const formData = new FormData();\n      formData.append(''avatar'', file);\n      const res = await apiFetch(`/api/users/${props.userId}/avatar`, {\n        method: ''POST'', body: formData,\n      });\n      if (!res.ok) throw new Error(''Upload failed'');\n      const data = await res.json();\n      user = { ...user, avatarUrl: data.avatarUrl };\n      isUploadingAvatar = false;\n    } catch (e) {\n      avatarError = e.message;\n      isUploadingAvatar = false;\n    }\n  }\n\n  // Validate form\n  function validateForm() {\n    const errors = {};\n    if (!formName || formName.trim().length < 2) errors.name = ''Name must be at least 2 characters'';\n    if (!formEmail || !/^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/.test(formEmail)) errors.email = ''Invalid email'';\n    if (formBio && formBio.length > 500) errors.bio = ''Bio must be under 500 characters'';\n    return errors;\n  }\n\n  // Handle save\n  async function handleSave() {\n    const errors = validateForm();\n    if (Object.keys(errors).length > 0) {\n      saveError = Object.values(errors).join(''; '');\n      return;\n    }\n    isSaving = true;\n    saveError = null;\n    try {\n      const res = await apiFetch(`/api/users/${props.userId}`, {\n        method: ''PATCH'',\n        headers: { ''Content-Type'': ''application/json'' },\n        body: JSON.stringify({ name: formName, email: formEmail, bio: formBio }),\n      });\n      if (!res.ok) throw new Error(''Save failed'');\n      const data = await res.json();\n      user = { ...user, name: formName, email: formEmail, bio: formBio };\n      isEditing = false;\n      isSaving = false;\n    } catch (e) {\n      saveError = e.message;\n      isSaving = false;\n    }\n  }\n\n  // Handle cancel\n  function handleCancel() {\n    formName = user ? user.name || '''' : '''';\n    formEmail = user ? user.email || '''' : '''';\n    formBio = user ? user.bio || '''' : '''';\n    saveError = null;\n    isEditing = false;\n  }\n\n  // Render helpers \u2014 all inline in the same function\n  function renderAvatar() {\n    const src = avatarPreview || (user && user.avatarUrl) || ''/default-avatar.png'';\n    return { type: ''img'', src, alt: `${user ? user.name : ''User''} avatar`, className: ''avatar'' };\n  }\n\n  function renderActivityItem(item) {\n    const icons = { login: ''\ud83d\udd11'', update: ''\u270f\ufe0f'', upload: ''\ud83d\udce4'', default: ''\u2022'' };\n    const icon = icons[item.type] || icons.default;\n    return {\n      type: ''li'',\n      key: item.id,\n      children: [`${icon} ${item.description} \u2014 ${new Date(item.timestamp).toLocaleDateString()}`],\n    };\n  }\n\n  function renderActivity() {\n    if (activityLoading) return { type: ''p'', children: [''Loading activity\u2026''] };\n    if (activityError) return { type: ''p'', className: ''error'', children: [activityError] };\n    if (activity.length === 0) return { type: ''p'', children: [''No recent activity.''] };\n    return { type: ''ul'', children: activity.map(renderActivityItem) };\n  }\n\n  function renderForm() {\n    if (!isEditing) {\n      return {\n        type: ''div'',\n        children: [\n          { type: ''p'', children: [user ? user.name : ''''] },\n          { type: ''p'', children: [user ? user.email : ''''] },\n          { type: ''p'', children: [user && user.bio ? user.bio : ''No bio set.''] },\n          { type: ''button'', onClick: () => { isEditing = true; }, children: [''Edit Profile''] },\n        ],\n      };\n    }\n    return {\n      type: ''form'',\n      onSubmit: handleSave,\n      children: [\n        saveError ? { type: ''p'', className: ''error'', children: [saveError] } : null,\n        { type: ''label'', children: [''Name'', { type: ''input'', value: formName, onChange: v => { formName = v; } }] },\n        { type: ''label'', children: [''Email'', { type: ''input'', value: formEmail, onChange: v => { formEmail = v; } }] },\n        { type: ''label'', children: [''Bio'', { type: ''textarea'', value: formBio, onChange: v => { formBio = v; } }] },\n        { type: ''button'', type: ''submit'', disabled: isSaving, children: [isSaving ? ''Saving\u2026'' : ''Save''] },\n        { type: ''button'', onClick: handleCancel, children: [''Cancel''] },\n      ].filter(Boolean),\n    };\n  }\n\n  // Top-level render output\n  if (isLoading) return { type: ''div'', children: [{ type: ''p'', children: [''Loading profile\u2026''] }] };\n  if (error)     return { type: ''div'', children: [{ type: ''p'', className: ''error'', children: [error] }] };\n\n  return {\n    type: ''div'',\n    className: ''profile-page'',\n    children: [\n      { type: ''section'', className: ''avatar-section'',\n        children: [\n          renderAvatar(),\n          avatarError ? { type: ''p'', className: ''error'', children: [avatarError] } : null,\n          isUploadingAvatar ? { type: ''p'', children: [''Uploading\u2026''] } : null,\n          { type: ''input'', inputType: ''file'', accept: ''image/*'',\n            onChange: f => handleAvatarChange(f) },\n        ].filter(Boolean),\n      },\n      { type: ''section'', className: ''profile-section'', children: [renderForm()] },\n      { type: ''section'', className: ''activity-section'',\n        children: [{ type: ''h2'', children: [''Recent Activity''] }, renderActivity()] },\n    ],\n  };\n}\n\nmodule.exports = { ProfilePage };\n"}]'
